  ('bookkeeper-moex-01646', 'bookkeeper', 'bookkeeper-moex-101-a2a4e0d3', 'sub-bookkeeper-03', NULL, 'single_choice', '陳先生於民國101年7月份死亡，其遺產中有一筆公告現值300萬元、市價600萬元的土地，此筆土地 乃陳先生於民國93年8月份繼承而得，且當年已繳納遺產稅。試問此筆土地應計入陳先生遺產總額的數 額為何？', '["無須計入", "120萬元", "180萬元", "240萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "1ccfab16e12c", "answer_pdf_sha1": "2a4c3ea58a0f", "source_family": "moex-gov-tw", "moex": {"exam_code": "101180", "c": "602", "s": "1304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務相關法規概要", "year": "101", "exam_name": "101年專技建築師技師第二次食品技師考試、不動產經紀人記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
